// generar_211_fix_tipos_test_rapido.js
// CHIQUI Entre Señales — Corrección del error de build del generar_210
//
// Qué corrige:
// El build de Vercel falló con un error de TypeScript en
// components/ExamenesLab.tsx: las dos ramas del guardado (test rápido
// vs exámenes con rangos) producían tipos distintos y el cliente de
// Supabase rechazaba la unión. Ahora ambas ramas usan un tipo común
// explícito (ResultadoInsert), que es la forma correcta de resolverlo.
//
// Solo reescribe components/ExamenesLab.tsx.
// ExamenesLabVet.tsx no se toca (quedó bien en el 210).
// No hay SQL nuevo (el sql_210 ya corrió bien).
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_211_fix_tipos_test_rapido.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'components/ExamenesLab.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo escrito correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
